import sys

def main():
    import sys
    input = sys.stdin.read
    data = input().split('\n')

    T = data[0]
    N = int(data[1])

    bags = []
    for i in range(2, len(data)):
        if not data[i]:
            continue
        parts = data[i].split()
        A_i = int(parts[0])
        strings = parts[1:]
        bags.append(strings)

    # DP[i] = minimum cost to form the first i characters of T
    dp = [float('inf')] * (len(T) + 1)
    dp[0] = 0

    for i in range(1, N + 1):
        new_dp = [float('inf')] * (len(T) + 1)
        for j in range(len(T) + 1):
            if dp[j] != float('inf'):
                # Option 1: Do nothing
                new_dp[j] = min(new_dp[j], dp[j])

        for s in bags[i - 1]:
            for j in range(len(T) + 1):
                if dp[j] != float('inf'):
                    if T.startswith(s, j):
                        new_dp[j + len(s)] = min(new_dp[j + len(s)], dp[j] + 1)
        dp = new_dp

    result = dp[len(T)]
    print(result if result != float('inf') else -1)

if __name__ == "__main__":
    main()
